async function step(name) {
  console.log(`${name}: before await`);
  await Promise.resolve();
  console.log(`${name}: after await`);
}

console.log("sync 1");
step("A");
step("B");
console.log("sync 2");

console.log("sync start");

setTimeout(() => console.log("macrotask"), 0);

queueMicrotask(() => console.log("microtask via queueMicrotask"));

Promise.resolve().then(() => console.log("microtask via Promise"));

console.log("sync end");

const start = Date.now();

setTimeout(() => {
  const delay = Date.now() - start;
  console.log(`setTimeout fired after ${delay}ms (requested 100ms)`);
}, 100);

// Block the event loop with sync work:
console.log("Starting sync work...");
const end = start + 300; // block for 300ms
while (Date.now() < end) {} // busy wait
console.log("Sync work done.");
